[GRAPH] scripts.generate_identifier_pattern.build_pattern:
def build_pattern(ranges):
    out = []

    for a, b in ranges:
        if a == b:  # single char
            out.append(a)
        elif ord(b) - ord(a) == 1:  # two chars, range is redundant
            out.append(a)
            out.append(b)
        else:
            out.append(f"{a}-{b}")

    return "".join(out)


