    def _cache_support(self, name, timeout, caller):
        key = self.environment.fragment_cache_prefix + name

        rv = self.environment.fragment_cache.get(key)
        if rv is not None:
            return rv
        rv = caller()
        self.environment.fragment_cache.add(key, rv, timeout)
        return rv

